section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/jtbd-switch-interview.json",
  "title": "JTBD Switch Interview",
  "type": "object",
  "required": [
    "artefact_id",
    "interviewee_id",
    "transcript_ref",
    "forces",
    "switch_decision",
    "verbatim_quotes",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "interviewee_id": {
      "type": "string",
      "description": "anonymized id",
      "minLength": 1
    },
    "transcript_ref": {
      "type": "string",
      "description": "URI to verbatim transcript",
      "minLength": 1
    },
    "forces": {
      "type": "object",
      "description": "push, pull, anxiety, habit each scored 0-10"
    },
    "switch_decision": {
      "type": "string",
      "description": "switched | considered | stayed",
      "minLength": 1
    },
    "verbatim_quotes": {
      "type": "array",
      "description": "at least one per force",
      "minItems": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
